#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long W,X,Y,Z; scanf("%lld %lld %lld %lld",&W,&X,&Y,&Z);
        int ok = (W==X)||(W==Y)||(W==Z)||(W==X+Y)||(W==X+Z)||(W==Y+Z)||(W==X+Y+Z);
        printf("%s\n", ok?"YES":"NO");
    }
    return 0;
}

