code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        W = int(next(it)); X = int(next(it)); Y = int(next(it)); Z = int(next(it))
        ok = (W==X) or (W==Y) or (W==Z) or (W==X+Y) or (W==X+Z) or (W==Y+Z) or (W==X+Y+Z)
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

